/**
 * 知识图谱「唯一事实来源」(single source of truth)。
 *
 * 全局图谱、每章图谱、交互式 HTML、关联文章索引——全部由这一个文件生成。
 * 想新增一个概念 / 一条关系 / 一篇延伸文章，只改这里，然后跑：
 *
 *     npm run kg        （等价 npx tsx knowledge-graph/generate.ts）
 *
 * 所有产物会自动重生成，无需手改任何 README。这就是「数据驱动 + 可持续扩展」。
 */

export interface ChapterDemo {
  /** 相对仓库根的 demo 入口；默认 `${dir}/index.ts`。 */
  entry?: string;
  /** 运行前需要的本地配置。`embedding` 表示还需要 OPENAI_API_KEY。 */
  needsKey?: "none" | "llm" | "embedding";
  /** 需要 stdin 的 demo 不进一键运行白名单。 */
  interactive?: boolean;
  /** 常驻 HTTP/server demo 不进一键运行白名单。 */
  needsServer?: boolean;
}

/** 课程的一个单元（19 章 + 毕业项目）。 */
export interface Chapter {
  /** 稳定 id：lesson 用两位编号 "01".."19"，毕设用 "capstone"。 */
  id: string;
  /** 目录名（用于生成相对链接）。 */
  slug: string;
  title: string;
  /** 所属部分（用于全局图谱按部分聚类）。 */
  part: string;
  /** 仓库内目录（含 README.md 的那层）。 */
  dir: string;
  /** 网页内运行器元数据；缺省表示没有一键运行入口。 */
  demo?: ChapterDemo;
}

/** 一个知识点 / 概念节点。 */
export interface Concept {
  /** 全局唯一 slug（kebab-case），如 "agent-loop"。 */
  id: string;
  /** 展示名，如 "Agent 循环"。 */
  label: string;
  /** 所属章节 id（必须存在于 CHAPTERS）。 */
  chapter: string;
  /** 一句话说明（可空）。 */
  summary?: string;
}

/** 概念之间的关系类型。 */
export type RelationType = "前置" | "深化" | "对比" | "应用" | "组成";

/** 一条有向关系边：from --(type)--> to。 */
export interface Relation {
  from: string;
  to: string;
  type: RelationType;
  note?: string;
}

/** 一篇关联 / 延伸文章（外部权威来源或内部交叉引用）。 */
export type FrontierEcosystemLayer =
  | "foundation"
  | "model-platform"
  | "protocol"
  | "runtime"
  | "product-ui"
  | "data-memory"
  | "evaluation"
  | "security-governance";

export interface Article {
  title: string;
  url: string;
  kind: "paper" | "doc" | "blog" | "video" | "internal";
  /** 发布方 / 原始来源；用于生成“来源：X · 可点击原文”。缺省时生成器用域名兜底。 */
  source?: string;
  /** 关联到哪些章节（章节 id 列表）。 */
  chapters: string[];
  note?: string;
  /** 第 19 章前沿生态归档使用的体系层；其他章节可不填。 */
  ecosystemLayer?: FrontierEcosystemLayer;
}

